# Combine all cases into a single list
# ═══════════════════════════════════════════════════════════════════════

ALL_CASES = CLEAN_PROSE + LEGIT_NUMBERS + TECHNICAL_CONTENT + PROPER_NOUNS + ACRONYMS + EDGE_CASES + EXTRA_CASES


# ═══════════════════════════════════════════════════════════════════════
# Test function
# ═══════════════════════════════════════════════════════════════════════


@pytest.mark.integration
@pytest.mark.ocr_negative
@pytest.mark.parametrize("text,test_id", ALL_CASES)
def test_ocr_clean_text(text, test_id, api):
    """Clean text should not trigger any OCR error detection."""
    body = ocr_check(api, text)
    assert body["result"] == "ok", f"[{test_id}] False positive on clean text: {text}"
    assert len(body.get("spans", [])) == 0, f"[{test_id}] Unexpected spans: {body['spans']}"
